import React, { useState } from 'react';

const Survey: React.FC = () => {
  const [submitted, setSubmitted] = useState(false);
  const [formData, setFormData] = useState({
    dob: '',
    income: '50000',
    allocation: '500',
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitted(true);
  };

  if (submitted) {
    return (
      <div className="max-w-2xl mx-auto text-center py-20 px-6 animate-fade-in">
        <div className="w-20 h-20 bg-premium-gold rounded-full flex items-center justify-center mx-auto mb-8 shadow-xl">
           <svg className="w-10 h-10 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" /></svg>
        </div>
        <h2 className="text-4xl serif mb-4 text-slate-900">Information Received</h2>
        <p className="text-slate-500 mb-8 font-light">Thank you. Roland will personally analyze these details to prepare a strategy that fits your profile.</p>
        <button 
          onClick={() => setSubmitted(false)}
          className="text-premium-gold font-bold uppercase tracking-widest text-xs hover:underline"
        >
          Edit Information
        </button>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto px-6">
      <div className="text-center mb-16">
        <h2 className="text-xs uppercase tracking-[0.3em] font-bold text-premium-gold mb-4">Strategic Assessment</h2>
        <h3 className="text-4xl md:text-5xl serif mb-6">Let's blueprint your security.</h3>
        <p className="text-slate-500 font-light max-w-xl mx-auto">Providing these details helps Roland understand your current financial horizon and tailor his advocacy to your specific needs.</p>
      </div>

      <form onSubmit={handleSubmit} className="bg-white p-10 md:p-16 rounded-[3rem] shadow-2xl border border-slate-50 relative overflow-hidden">
        <div className="absolute top-0 right-0 w-32 h-32 bg-premium-gold/5 rounded-bl-full"></div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-12 relative z-10">
          <div className="space-y-8">
            <div className="space-y-3">
              <label className="text-xs uppercase tracking-widest font-bold text-slate-400">Date of Birth</label>
              <input 
                required
                type="date" 
                value={formData.dob}
                onChange={e => setFormData({...formData, dob: e.target.value})}
                className="w-full bg-slate-50 border-b-2 border-slate-200 py-4 px-4 rounded-t-xl outline-none focus:border-premium-gold transition-colors text-slate-900 font-medium"
              />
              <p className="text-[10px] text-slate-400 italic">Age is a critical factor in identifying the most efficient policies.</p>
            </div>

            <div className="space-y-3">
              <label className="text-xs uppercase tracking-widest font-bold text-slate-400">Annual Income Estimate (USD)</label>
              <div className="flex items-center gap-4">
                <input 
                  type="range" 
                  min="10000" 
                  max="500000" 
                  step="5000"
                  value={formData.income}
                  onChange={e => setFormData({...formData, income: e.target.value})}
                  className="flex-1 accent-premium-gold cursor-pointer"
                />
                <span className="text-lg font-bold text-premium-dark min-w-[100px] text-right">
                  ${Number(formData.income).toLocaleString()}
                </span>
              </div>
            </div>
          </div>

          <div className="space-y-8">
            <div className="space-y-3">
              <label className="text-xs uppercase tracking-widest font-bold text-slate-400">Monthly Allocation Budget</label>
              <div className="flex items-center gap-4">
                 <input 
