import React, { useState } from 'react';

const SERVICES_LIST = [
  'Life Insurance',
  'Disability Insurance',
  'Critical Illness Insurance',
  'Car Insurance',
  'Medical Insurance',
  'Property Insurance',
  'Marine Insurance',
  'Group Insurance'
];

const TIME_SLOTS = [
  '09:00 AM', '10:00 AM', '11:00 AM', 
  '01:00 PM', '02:00 PM', '03:00 PM', '04:00 PM'
];

const Survey: React.FC = () => {
  const [step, setStep] = useState(1);
  const [submitted, setSubmitted] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    dob: '',
    income: '75000',
    allocation: '500',
    selectedServices: [] as string[],
    date: '',
    time: ''
  });

  const [currentMonth, setCurrentMonth] = useState(new Date());

  const handleServiceToggle = (service: string) => {
    setFormData(prev => ({
      ...prev,
      selectedServices: prev.selectedServices.includes(service)
        ? prev.selectedServices.filter(s => s !== service)
        : [...prev.selectedServices, service]
    }));
  };

  const nextStep = () => setStep(s => s + 1);
  const prevStep = () => setStep(s => s - 1);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitted(true);
  };

  // Simple calendar logic
  const daysInMonth = (year: number, month: number) => new Date(year, month + 1, 0).getDate();
  const firstDayOfMonth = (year: number, month: number) => new Date(year, month, 1).getDay();

  const renderCalendar = () => {
    const year = currentMonth.getFullYear();
    const month = currentMonth.getMonth();
    const totalDays = daysInMonth(year, month);
    const startOffset = firstDayOfMonth(year, month);
    const days = [];

    for (let i = 0; i < startOffset; i++) {
      days.push(<div key={`empty-${i}`} className="h-12 w-12" />);
    }

    for (let d = 1; d <= totalDays; d++) {
      const dateString = `${year}-${String(month + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
      const isSelected = formData.date === dateString;
      const isPast = new Date(year, month, d) < new Date(new Date().setHours(0,0,0,0));

      days.push(
        <button
          key={d}
          type="button"
          disabled={isPast}
          onClick={() => setFormData({ ...formData, date: dateString })}
          className={`h-12 w-12 rounded-full flex items-center justify-center text-sm transition-all
            ${isPast ? 'text-slate-200 cursor-not-allowed' : 'text-slate-700 hover:bg-premium-gold/10'}
            ${isSelected ? 'bg-premium-dark text-white font-bold scale-110' : ''}
          `}
        >
          {d}
        </button>
      );
    }
    return days;
  };

  if (submitted) {
    return (
      <div className="max-w-2xl mx-auto text-center py-24 px-6 animate-fade-in">
        <div className="w-24 h-24 bg-premium-gold rounded-full flex items-center justify-center mx-auto mb-10 shadow-2xl">
           <svg className="w-12 h-12 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" /></svg>
        </div>
        <h2 className="text-5xl serif mb-6 text-slate-900">Consultation Scheduled</h2>
        <p className="text-slate-500 mb-10 text-lg font-light leading-relaxed">
          Confirmed for <span className="font-bold text-premium-dark">{formData.date}</span> at <span className="font-bold text-premium-dark">{formData.time}</span>.<br/>
          Roland has received your details and will contact you at <span className="italic">{formData.email}</span> to finalize the meeting link.
        </p>
        <button 
          onClick={() => { setSubmitted(false); setStep(1); }}
          className="bg-premium-dark text-white px-10 py-4 rounded-full text-xs uppercase tracking-widest font-bold hover:bg-slate-800 transition-all"
        >
          Book Another Session
        </button>
      </div>
    );
  }

  return (
    <div className="max-w-5xl mx-auto px-6">
      <div className="text-center mb-16">
        <h2 className="text-xs uppercase tracking-[0.4em] font-bold text-premium-gold mb-4">The Roland Approach</h2>
        <h3 className="text-4xl md:text-5xl serif mb-6">Secure Your Free Consultation</h3>
        <div className="flex justify-center items-center gap-4 mb-8">
          {[1, 2, 3].map(i => (
            <div key={i} className={`h-1.5 w-12 rounded-full transition-all duration-500 ${step >= i ? 'bg-premium-gold' : 'bg-slate-100'}`} />
          ))}
        </div>
      </div>

      <div className="bg-white rounded-[3.5rem] shadow-2xl border border-slate-50 overflow-hidden min-h-[650px] flex flex-col md:flex-row">
        {/* Left Sidebar Info */}
        <div className="w-full md:w-1/3 bg-premium-dark p-12 text-white flex flex-col justify-between">
          <div>
            <h4 className="text-2xl serif mb-6 text-premium-gold italic">Step {step} of 3</h4>
            <p className="text-slate-400 font-light leading-relaxed">
              {step === 1 && "Start by introducing yourself and your current financial landscape."}
              {step === 2 && "Select the pillars of protection you are interested in exploring."}
              {step === 3 && "Finally, choose a window of time that suits your schedule."}
            </p>
          </div>
          <div className="space-y-4 pt-10">
             <div className="flex items-center gap-4 text-xs font-bold tracking-widest text-slate-500">
               <div className="w-2 h-2 rounded-full bg-premium-gold"></div>
               PRIVATE ADVOCACY
             </div>
             <div className="flex items-center gap-4 text-xs font-bold tracking-widest text-slate-500">
               <div className="w-2 h-2 rounded-full bg-premium-gold"></div>
               NO-OBLIGATION
             </div>
          </div>
        </div>

        {/* Form Area */}
        <form onSubmit={handleSubmit} className="flex-1 p-8 md:p-16 flex flex-col">
          {step === 1 && (
            <div className="space-y-8 animate-fade-in flex-1">
              <div className="grid md:grid-cols-2 gap-8">
                <div className="space-y-2">
                  <label className="text-[10px] uppercase tracking-[0.2em] font-bold text-slate-400">Full Name</label>
                  <input required type="text" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full bg-slate-50 border-b-2 border-slate-200 py-3 px-4 outline-none focus:border-premium-gold transition-colors font-medium" placeholder="E.g. Julian Wright" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] uppercase tracking-[0.2em] font-bold text-slate-400">Email</label>
                  <input required type="email" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} className="w-full bg-slate-50 border-b-2 border-slate-200 py-3 px-4 outline-none focus:border-premium-gold transition-colors font-medium" placeholder="julian@example.com" />
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] uppercase tracking-[0.2em] font-bold text-slate-400">Date of Birth</label>
                <input required type="date" value={formData.dob} onChange={e => setFormData({...formData, dob: e.target.value})} className="w-full bg-slate-50 border-b-2 border-slate-200 py-3 px-4 outline-none focus:border-premium-gold transition-colors font-medium" />
              </div>
              <div className="space-y-6 pt-4">
                <div className="space-y-2">
                  <label className="text-[10px] uppercase tracking-[0.2em] font-bold text-slate-400">Annual Income Estimate: <span className="text-premium-dark">${Number(formData.income).toLocaleString()}</span></label>
                  <input type="range" min="20000" max="1000000" step="10000" value={formData.income} onChange={e => setFormData({...formData, income: e.target.value})} className="w-full accent-premium-gold cursor-pointer" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] uppercase tracking-[0.2em] font-bold text-slate-400">Monthly Allocation Budget: <span className="text-premium-dark">${Number(formData.allocation).toLocaleString()}</span></label>
