                </div>
              </div>
            </div>
          )}

          {step === 2 && (
            <div className="space-y-8 animate-fade-in flex-1">
              <h4 className="text-sm uppercase tracking-widest font-bold text-slate-400 mb-6">Select services of interest (Choose multiple)</h4>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                {SERVICES_LIST.map(service => (
                  <button
                    key={service}
                    type="button"
                    onClick={() => handleServiceToggle(service)}
                    className={`text-left p-4 rounded-2xl border-2 transition-all flex items-center justify-between
                      ${formData.selectedServices.includes(service) 
                        ? 'border-premium-gold bg-premium-gold/5 text-premium-dark font-bold' 
                        : 'border-slate-100 bg-white text-slate-500 hover:border-slate-300'}
                    `}
                  >
                    <span className="text-sm">{service}</span>
                    {formData.selectedServices.includes(service) && (
                      <svg className="w-4 h-4 text-premium-gold" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" /></svg>
                    )}
                  </button>
                ))}
              </div>
            </div>
          )}

          {step === 3 && (
            <div className="space-y-8 animate-fade-in flex-1">
              <div className="flex flex-col lg:flex-row gap-12">
                <div className="flex-1">
                  <div className="flex items-center justify-between mb-4 px-2">
                    <h5 className="font-bold text-slate-900">{currentMonth.toLocaleString('default', { month: 'long', year: 'numeric' })}</h5>
                    <div className="flex gap-2">
                      <button type="button" onClick={() => setCurrentMonth(new Date(currentMonth.setMonth(currentMonth.getMonth() - 1)))} className="p-1 hover:text-premium-gold"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 19l-7-7 7-7" /></svg></button>
                      <button type="button" onClick={() => setCurrentMonth(new Date(currentMonth.setMonth(currentMonth.getMonth() + 1)))} className="p-1 hover:text-premium-gold"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7" /></svg></button>
                    </div>
                  </div>
                  <div className="grid grid-cols-7 gap-1 text-center text-[10px] font-bold text-slate-300 uppercase tracking-widest mb-2">
                    {['S','M','T','W','T','F','S'].map((d,i) => <div key={i}>{d}</div>)}
                  </div>
                  <div className="grid grid-cols-7 gap-1">
                    {renderCalendar()}
                  </div>
                </div>

                <div className="lg:w-48 space-y-4">
                  <h5 className="text-[10px] uppercase tracking-widest font-bold text-slate-400 mb-2">Select Time</h5>
                  <div className="grid grid-cols-2 lg:grid-cols-1 gap-2">
                    {TIME_SLOTS.map(t => (
                      <button
                        key={t}
                        type="button"
                        onClick={() => setFormData({...formData, time: t})}
                        className={`py-3 px-4 rounded-xl border text-xs font-bold transition-all
                          ${formData.time === t ? 'bg-premium-gold text-white border-premium-gold' : 'bg-slate-50 border-slate-100 text-slate-500 hover:border-slate-300'}
                        `}
                      >
                        {t}
                      </button>
                    ))}
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* Navigation */}
          <div className="pt-12 flex items-center justify-between mt-auto">
            {step > 1 ? (
              <button type="button" onClick={prevStep} className="text-slate-400 text-xs uppercase tracking-widest font-bold hover:text-premium-dark flex items-center gap-2">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7 7-7" /></svg> Back
              </button>
            ) : <div />}

            {step < 3 ? (
              <button 
                type="button" 
                onClick={nextStep} 
                disabled={step === 1 && (!formData.name || !formData.email || !formData.dob)}
                className="bg-premium-dark text-white px-12 py-5 rounded-full text-xs uppercase tracking-widest font-bold hover:bg-slate-800 transition-all disabled:opacity-30"
              >
                Continue
              </button>
            ) : (
              <button 
                type="submit" 
                disabled={!formData.date || !formData.time}
                className="bg-premium-gold text-white px-12 py-5 rounded-full text-xs uppercase tracking-widest font-bold hover:bg-opacity-90 transition-all shadow-xl shadow-premium-gold/20 disabled:opacity-30"
              >
                Finalize Booking
              </button>
            )}
          </div>
        </form>
      </div>
    </div>
  );
};

