import Survey from './components/Survey';
import GeminiAssistant from './components/GeminiAssistant';
import Footer from './components/Footer';

const App: React.FC = () => {
  const [activeSection, setActiveSection] = useState('home');

  useEffect(() => {
    const handleScroll = () => {
      const sections = ['home', 'about', 'services', 'consultation', 'contact'];
      const scrollPosition = window.scrollY + 100;

      for (const section of sections) {
        const element = document.getElementById(section);
        if (element && scrollPosition >= element.offsetTop && scrollPosition < element.offsetTop + element.offsetHeight) {
          setActiveSection(section);
          break;
        }
      }
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <div className="min-h-screen selection:bg-premium-gold selection:text-white bg-warm-canvas">
      <Header activeSection={activeSection} />
      <main>
        <section id="home">
          <Hero />
        </section>
        <Stats />
        <section id="about">
          <About />
        </section>
        <section id="services">
          <Services />
        </section>
        <section id="consultation" className="py-32 bg-white border-y border-gray-100">
          <Survey />
        </section>
        <GeminiAssistant />
      </main>
      <section id="contact">
        <Footer />
      </section>
    </div>
  );
};

export default App;

