import React, { useState } from 'react';

const TIME_SLOTS = [
  '09:00 AM', '10:00 AM', '11:00 AM', 
  '01:00 PM', '02:00 PM', '03:00 PM', '04:00 PM'
];

const SERVICES = [
  'Life Insurance', 'Medical Insurance', 'Property Insurance', 
  'Car Insurance', 'Disability Insurance', 'Critical Illness'
];

const Survey: React.FC = () => {
  const [step, setStep] = useState(1);
  const [submitted, setSubmitted] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    dob: '',
    service: '',
    income: '75000',
    allocation: '500',
    date: '',
    time: ''
  });

  const [currentMonth, setCurrentMonth] = useState(new Date());

  const nextStep = () => setStep(s => s + 1);
  const prevStep = () => setStep(s => s - 1);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitted(true);
  };

  const daysInMonth = (year: number, month: number) => new Date(year, month + 1, 0).getDate();
  const firstDayOfMonth = (year: number, month: number) => new Date(year, month, 1).getDay();

  const renderCalendar = () => {
    const year = currentMonth.getFullYear();
    const month = currentMonth.getMonth();
    const totalDays = daysInMonth(year, month);
    const startOffset = firstDayOfMonth(year, month);
    const days = [];

    for (let i = 0; i < startOffset; i++) {
      days.push(<div key={`empty-${i}`} className="h-12 w-12" />);
    }

    for (let d = 1; d <= totalDays; d++) {
      const dateString = `${year}-${String(month + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
      const isSelected = formData.date === dateString;
      const isPast = new Date(year, month, d) < new Date(new Date().setHours(0,0,0,0));

      days.push(
        <button
          key={d}
          type="button"
          disabled={isPast}
          onClick={() => setFormData({ ...formData, date: dateString })}
          className={`h-12 w-12 rounded-full flex items-center justify-center text-sm transition-all
            ${isPast ? 'text-slate-200 cursor-not-allowed' : 'text-slate-700 hover:bg-premium-gold/10'}
            ${isSelected ? 'bg-premium-gold text-white font-bold scale-110 shadow-lg shadow-premium-gold/30' : ''}
          `}
        >
          {d}
        </button>
      );
    }
    return days;
  };

  if (submitted) {
    return (
      <div className="max-w-2xl mx-auto text-center py-24 px-6 animate-fade-in">
        <div className="w-24 h-24 gold-gradient rounded-full flex items-center justify-center mx-auto mb-10 shadow-2xl animate-float">
           <svg className="w-12 h-12 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" /></svg>
        </div>
        <h2 className="text-5xl serif mb-6 text-slate-900">Session Confirmed</h2>
        <p className="text-slate-500 mb-10 text-lg font-light leading-relaxed">
          Your free consultation regarding <span className="font-bold text-premium-gold">{formData.service}</span> is set for <span className="font-bold text-premium-dark">{formData.date}</span> at <span className="font-bold text-premium-dark">{formData.time}</span>.<br/>
          Roland will reach out via <span className="italic text-premium-gold font-medium">{formData.email}</span> with the meeting invitation.
        </p>
        <button 
          onClick={() => { setSubmitted(false); setStep(1); }}
          className="bg-premium-dark text-white px-10 py-4 rounded-full text-xs uppercase tracking-widest font-bold hover:bg-slate-800 transition-all"
        >
          Schedule Another
        </button>
      </div>
    );
  }

  return (
    <div className="max-w-5xl mx-auto px-6">
      <div className="text-center mb-16">
        <h2 className="text-xs uppercase tracking-[0.4em] font-bold text-premium-gold mb-4">Direct Advocacy</h2>
        <h3 className="text-4xl md:text-5xl serif mb-6">Book Your <span className="text-premium-gold italic">Free</span> Consultation</h3>
        <div className="flex justify-center items-center gap-4 mb-8">
          {[1, 2].map(i => (
            <div key={i} className={`h-1.5 w-16 rounded-full transition-all duration-500 ${step >= i ? 'bg-premium-gold' : 'bg-slate-100'}`} />
          ))}
        </div>
      </div>

      <div className="bg-white rounded-[3.5rem] shadow-[0_32px_64px_-16px_rgba(0,0,0,0.1)] border border-slate-50 overflow-hidden min-h-[600px] flex flex-col md:flex-row">
        {/* Left Visual Sidebar */}
        <div className="w-full md:w-1/3 bg-premium-dark p-12 text-white flex flex-col justify-between relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-full opacity-10 pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]"></div>
          <div className="relative z-10">
            <h4 className="text-2xl serif mb-6 text-premium-gold italic">Step {step} of 2</h4>
            <p className="text-slate-400 font-light leading-relaxed">
              {step === 1 && "Provide your profile details and select the service you are interested in to help Roland prepare a personalized strategy."}
              {step === 2 && "Choose a convenient window for your session. All times are in Lebanon local time."}
            </p>
          </div>
          <div className="space-y-6 pt-10 relative z-10">
             <div className="p-4 bg-white/5 rounded-2xl border border-white/10 backdrop-blur-sm">
                <div className="text-[10px] uppercase tracking-widest font-bold text-premium-gold mb-1">Confidential</div>
                <p className="text-xs text-slate-400">Your data is handled with the highest level of professional discretion.</p>
             </div>
          </div>
        </div>

        {/* Form Body */}
        <form onSubmit={handleSubmit} className="flex-1 p-8 md:p-16 flex flex-col bg-white">
          {step === 1 && (
            <div className="space-y-8 animate-fade-in flex-1">
              <div className="grid md:grid-cols-2 gap-8">
                <div className="space-y-2">
                  <label className="text-[10px] uppercase tracking-[0.2em] font-bold text-slate-400">Full Name</label>
                  <input required type="text" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full bg-slate-50 border-b-2 border-slate-200 py-3 px-4 outline-none focus:border-premium-gold transition-colors font-medium rounded-t-lg" placeholder="Julian Wright" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] uppercase tracking-[0.2em] font-bold text-slate-400">Email for Confirmation</label>
                  <input required type="email" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} className="w-full bg-slate-50 border-b-2 border-slate-200 py-3 px-4 outline-none focus:border-premium-gold transition-colors font-medium rounded-t-lg" placeholder="julian@example.com" />
                </div>
              </div>

              <div className="grid md:grid-cols-2 gap-8">
                <div className="space-y-2">
                  <label className="text-[10px] uppercase tracking-[0.2em] font-bold text-slate-400">Date of Birth</label>
                  <input required type="date" value={formData.dob} onChange={e => setFormData({...formData, dob: e.target.value})} className="w-full bg-slate-50 border-b-2 border-slate-200 py-3 px-4 outline-none focus:border-premium-gold transition-colors font-medium rounded-t-lg" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] uppercase tracking-[0.2em] font-bold text-slate-400">Service of Interest</label>
                  <select required value={formData.service} onChange={e => setFormData({...formData, service: e.target.value})} className="w-full bg-slate-50 border-b-2 border-slate-200 py-3 px-4 outline-none focus:border-premium-gold transition-colors font-medium rounded-t-lg appearance-none cursor-pointer">
                    <option value="" disabled>Select a Service</option>
                    {SERVICES.map(s => <option key={s} value={s}>{s}</option>)}
                  </select>
                </div>
              </div>

              <div className="grid md:grid-cols-2 gap-12 pt-4">
                <div className="space-y-4">
                  <label className="text-[10px] uppercase tracking-[0.2em] font-bold text-slate-400">
                    Estimated Annual Income: <span className="text-premium-dark font-bold ml-2">${Number(formData.income).toLocaleString()}</span>
                  </label>
                  <input type="range" min="20000" max="1000000" step="5000" value={formData.income} onChange={e => setFormData({...formData, income: e.target.value})} className="w-full accent-premium-gold cursor-pointer" />
                </div>
                <div className="space-y-4">
                  <label className="text-[10px] uppercase tracking-[0.2em] font-bold text-slate-400">
                    Monthly Allocation: <span className="text-premium-dark font-bold ml-2">${Number(formData.allocation).toLocaleString()}</span>
                  </label>
                  <input type="range" min="100" max="15000" step="100" value={formData.allocation} onChange={e => setFormData({...formData, allocation: e.target.value})} className="w-full accent-premium-gold cursor-pointer" />
                </div>
              </div>
            </div>
          )}

          {step === 2 && (
            <div className="space-y-8 animate-fade-in flex-1">
              <div className="flex flex-col lg:flex-row gap-10">
                <div className="flex-1">
                  <div className="flex items-center justify-between mb-6 px-2">
                    <h5 className="font-bold text-slate-900 serif text-xl">{currentMonth.toLocaleString('default', { month: 'long', year: 'numeric' })}</h5>
                    <div className="flex gap-4">
                      <button type="button" onClick={() => setCurrentMonth(new Date(currentMonth.setMonth(currentMonth.getMonth() - 1)))} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 19l-7-7 7-7" /></svg></button>
                      <button type="button" onClick={() => setCurrentMonth(new Date(currentMonth.setMonth(currentMonth.getMonth() + 1)))} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7" /></svg></button>
                    </div>
                  </div>
                  <div className="grid grid-cols-7 gap-2 text-center text-[10px] font-bold text-slate-300 uppercase tracking-widest mb-4">
                    {['Sun','Mon','Tue','Wed','Thu','Fri','Sat'].map(d => <div key={d}>{d}</div>)}
                  </div>
                  <div className="grid grid-cols-7 gap-2">
                    {renderCalendar()}
                  </div>
                </div>

                <div className="lg:w-56">
                  <h5 className="text-[10px] uppercase tracking-widest font-bold text-slate-400 mb-6 px-1">Select Time Window</h5>
                  <div className="grid grid-cols-2 lg:grid-cols-1 gap-3">
                    {TIME_SLOTS.map(t => (
                      <button
                        key={t}
                        type="button"
                        onClick={() => setFormData({...formData, time: t})}
                        className={`py-3 px-4 rounded-xl border text-xs font-bold transition-all
                          ${formData.time === t ? 'bg-premium-dark text-white border-premium-dark shadow-xl' : 'bg-slate-50 border-slate-100 text-slate-500 hover:border-slate-300 hover:bg-white'}
                        `}
                      >
                        {t}
                      </button>
                    ))}
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* Navigation */}
          <div className="pt-12 flex items-center justify-between mt-auto">
            {step > 1 ? (
              <button type="button" onClick={prevStep} className="text-slate-400 text-xs uppercase tracking-widest font-bold hover:text-premium-dark flex items-center gap-2 group transition-colors">
                <svg className="w-4 h-4 group-hover:-translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7 7-7" /></svg> Back
              </button>
            ) : <div />}

            {step < 2 ? (
              <button 
                type="button" 
                onClick={nextStep} 
                disabled={!formData.name || !formData.email || !formData.dob || !formData.service}
                className="bg-premium-dark text-white px-12 py-5 rounded-full text-xs uppercase tracking-widest font-bold hover:bg-slate-800 transition-all disabled:opacity-30 disabled:cursor-not-allowed shadow-xl shadow-slate-900/20"
