                      <button
                        key={t}
                        type="button"
                        onClick={() => setFormData({...formData, time: t})}
                        className={`py-3 px-4 rounded-xl border text-xs font-bold transition-all
                          ${formData.time === t ? 'bg-premium-dark text-white border-premium-dark shadow-xl' : 'bg-slate-50 border-slate-100 text-slate-500 hover:border-slate-300 hover:bg-white'}
